import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ButtonHTMLAttributes, ReactElement, ReactNode } from 'react';
export interface TabProps extends ButtonHTMLAttributes<HTMLButtonElement> {
    /**
     * данные таба, будут переданы в обработчик при нажатии на таб
     *
     * Может пригодиться, например, для асинхронной подгрузки данный в момент клика и т.п
     */
    value?: any;
    /**
     * текст отображаемый в заголовке
     */
    label?: string;
    /**
     * Название иконки из библиотеки @beeline/design-tokens
     */
    iconName?: Icons;
    /**
     * имя css класса, будет присвоено корневому элементу
     */
    className?: string;
    /**
     * состояние заблокированности, компонент не будет реагировать на:
     *
     * 1. клик пользователя
     * 2. управление с клавиатуры
     * 3. програмное изменение индекса выбранного таба в родителе
     */
    disabled?: boolean;
    /**
     * обработчик нажатия на таб
     *
     * срабатывая передаст аргументом все что было указано в пропсе value
     *
     * Обработчик сработает только если пользователь кликнет на таб,
     * не сработает, например при програмном изменении индекса выбранного таба в родителе
     */
    onClick?: (value: any) => void;
    /**
     * номер таба, передавайте если вам нужен якорь для поиска в массиве табов
     */
    index?: number;
    /**
     * контент таба, будет отображен под всеми табами при выборе
     */
    children?: ReactNode;
    /**
     * Пропс из устаревшей реализации табов,
     * нужен для мягкого перехода, чтобы линтер пользователя не ругался на несуществующий пропс
     * @deprecated
     */
    selected?: boolean;
    /**
     * Пропс для класса для body у tab
     * нужен что бы стилизировать контент в табе
     */
    bodyClassName?: string;
    /**
     * Пропс для роутинг компонента
     */
    routingComponent?: ReactElement;
}
/**
 * служебные пропсы, передаются из родителя, нужны для взаимодействия между компонентами
 */
export interface InnerTabProps extends TabProps {
    /**
     * состояние выбранности, в нем табу нужно изменить свои стили, а родителю показать его контент
     */
    selected: boolean;
    /**
     * колбек вызываемый при выборе конкретного таба
     *
     * нужен чтобы передать в родителя отображаемый контент и html-элемент заголовка (нужен для рассчетов позиции индикатора)
     */
    onSelected: (data: CurrentTabData) => void;
}
/**
 * данные текущего таба, передаются в родительский компонент
 */
export interface CurrentTabData {
    /**
     * контент, который необходимо отобразить пользователю при выборе этого таба
     */
    tabBody: ReactNode;
    /**
     * html-элемент таба, передается родителю для рассчета позиции полоски-индикатора
     */
    tabElement?: HTMLDivElement;
    tabProps?: TabProps;
}
